const express = require('express');
const mongoose = require('mongoose');

const app = express();
app.use(express.json());

const queryBuilder = async (Model, filter = {}, projection = {}, sort = {}, options = {}) => {
    try {
        const query = Model.find(filter, projection, options).sort(sort);
        const results = await query.exec();
        return results;
    } catch (error) {
        throw new Error(error);
    }
};

// Example usage route
app.post('/api/search', async (req, res) => {
    const { filter, projection, sort } = req.body;

    try {
        const results = await queryBuilder(MyModel, filter, projection, sort);
        res.status(200).json(results);
    } catch (error) {
        res.status(500).json({ message: error.message });
    }
});

// Mongoose model example
const MyModel = mongoose.model('MyModel', new mongoose.Schema({
    name: String,
    age: Number,
    password: String,
    createdAt: { type: Date, default: Date.now }
}));

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
    console.log(`Server is running on port ${PORT}`);
});